use std::collections::HashSet;

fn main() {
    // Example of using for loop
    for i in 0..5 { // Iterate from 0 to 4
        println!("Number: {}", i);
    }

    // Example of using HashSet to compare data
    let set1: HashSet<i32> = vec![1, 2, 3, 4, 5].into_iter().collect();
    let set2: HashSet<i32> = vec![3, 4, 5, 6, 7].into_iter().collect();

    // Intersection of two sets
    let intersection: HashSet<_> = set1.intersection(&set2).collect();
    println!("Intersection: {:?}", intersection);

    // Difference of two sets
    let difference: HashSet<_> = set1.difference(&set2).collect();
    println!("Difference: {:?}", difference);

    // Union of two sets
    let union: HashSet<_> = set1.union(&set2).collect();
    println!("Union: {:?}", union);
}
```

