use std::collections::HashSet;

fn main() {
    let set1: HashSet<_> = vec![1, 2, 3, 4, 5].into_iter().collect();
    let set2: HashSet<_> = vec![4, 5, 6, 7, 8].into_iter().collect();
    let set3: HashSet<_> = vec![3, 7, 9, 10].into_iter().collect();

    let mut sets = vec![&set1, &set2, &set3];

    for (i, set) in sets.iter().enumerate() {
        for other_set in sets[i + 1..].iter() {
            let intersection: HashSet<_> = set.intersection(*other_set).copied().collect();
            let difference: HashSet<_> = set.difference(*other_set).copied().collect();
            let union: HashSet<_> = set.union(*other_set).copied().collect();

            println!("Intersection: {:?}", intersection);
            println!("Difference: {:?}", difference);
            println!("Union: {:?}", union);
        }
    }
}
```

